public function updateCartTime() {
    if ($this->request->server['REQUEST_METHOD'] == 'POST') {
        $this->db->query("UPDATE `" . DB_PREFIX . "cart` SET `date_added` = DATE_ADD(`date_added`, INTERVAL 30 SECOND) WHERE session_id = '" . $this->db->escape($this->session->getId()) . "'");
        $this->response->setOutput(json_encode(['success' => true]));
    }
}
